        ///<summary>
        ///Create Asset Metadata for an existing ASA, restricted to the ASA Manager Address.
        ///</summary>
        /// <param name="asset_id">The Asset ID to create the Asset Metadata for </param>
        /// <param name="reversible_flags">The Reversible Flags. WARNING: LSB and 1 can by set only at creation time </param>
        /// <param name="irreversible_flags">The Irreversible Flags. WARNING: if the MSB is True the Asset Metadata is IMMUTABLE </param>
        /// <param name="metadata_size">The Metadata byte size to be created </param>
        /// <param name="payload">The Metadata payload (without Header). WARNING: Payload larger than args capacity must be provided with arc89_extra_payload calls in the Group </param>
        /// <param name="mbr_delta_payment">Payment of the MBR Delta amount (microALGO) for the Asset Metadata Box creation </param>
        public async Task<Structs.MbrDelta> Arc89CreateMetadata(PaymentTransaction mbr_delta_payment, ulong asset_id, byte reversible_flags, byte irreversible_flags, ushort metadata_size, byte[] payload, Account _tx_sender, ulong? _tx_fee, string _tx_note = "", ulong _tx_roundValidity = 1000, List<BoxRef>? _tx_boxes = null, List<Transaction>? _tx_transactions = null, List<ulong>? _tx_assets = null, List<ulong>? _tx_apps = null, List<Address>? _tx_accounts = null, AVM.ClientGenerator.Core.OnCompleteType _tx_callType = AVM.ClientGenerator.Core.OnCompleteType.NoOp)
        {
            _tx_boxes ??= new List<BoxRef>();
            _tx_transactions ??= new List<Transaction>();
            _tx_assets ??= new List<ulong>();
            _tx_apps ??= new List<ulong>();
            _tx_accounts ??= new List<Address>();
            _tx_transactions.AddRange(new List<Transaction> { mbr_delta_payment });
            byte[] abiHandle = { 120, 64, 120, 49 };
            var asset_idAbi = new AVM.ClientGenerator.ABI.ARC4.Types.UInt64(); asset_idAbi.From(asset_id);
            var reversible_flagsAbi = new AVM.ClientGenerator.ABI.ARC4.Types.Byte(); reversible_flagsAbi.From(reversible_flags);
            var irreversible_flagsAbi = new AVM.ClientGenerator.ABI.ARC4.Types.Byte(); irreversible_flagsAbi.From(irreversible_flags);
            var metadata_sizeAbi = new AVM.ClientGenerator.ABI.ARC4.Types.UInt16(); metadata_sizeAbi.From(metadata_size);
            var payloadAbi = new AVM.ClientGenerator.ABI.ARC4.Types.VariableArray<AVM.ClientGenerator.ABI.ARC4.Types.Byte>("byte"); payloadAbi.From(payload);

            var result = await base.CallApp(new List<object> { abiHandle, asset_idAbi, reversible_flagsAbi, irreversible_flagsAbi, metadata_sizeAbi, payloadAbi, mbr_delta_payment }, _tx_fee: _tx_fee, _tx_callType: _tx_callType, _tx_roundValidity: _tx_roundValidity, _tx_note: _tx_note, _tx_sender: _tx_sender, _tx_transactions: _tx_transactions, _tx_apps: _tx_apps, _tx_assets: _tx_assets, _tx_accounts: _tx_accounts, _tx_boxes: _tx_boxes);
            var lastLogBytes = result.Last();
            if (lastLogBytes.Length < 4 || lastLogBytes[0] != 21 || lastLogBytes[1] != 31 || lastLogBytes[2] != 124 || lastLogBytes[3] != 117) throw new Exception("Invalid ABI handle");
            return Structs.MbrDelta.Parse(lastLogBytes.Skip(4).ToArray());

        }

